SELECT sc.name AS system_call_type_name, scc.name AS system_call_category_name
FROM system_call_types AS sc
INNER JOIN system_call_categories AS scc ON sc.category_id = scc.id;

SELECT DISTINCT sc.name
FROM system_call_types sc
INNER JOIN system_call_errors se ON sc.id = se.system_call_id;

SELECT name AS "System Call Type"
FROM system_call_types
WHERE subcategory_id = 5;

SELECT name, description, EXP(id), MIN(category_id) AS min_category_id
FROM system_call_types
WHERE category_id = 1 AND subcategory_id = 2;

SELECT sc.id, sc.name AS system_call_name, sr.reporting_data
FROM system_call_types AS sc
LEFT JOIN system_call_reporting AS sr ON sc.id = sr.system_call_id;

SELECT COUNT(*) as number_of_flowers, name
FROM system_call_types
GROUP BY name;

SELECT name 
FROM system_call_types
WHERE SINH(id) > 0;

SELECT name 
FROM system_call_types
WHERE id = (SELECT MAX(id) FROM system_call_types);
